function cssRuleContains(source, selector, declaration) {
  const escaped = selector.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
  const match = source.match(new RegExp(`${escaped}\\s*\\{([^}]*)\\}`));
  return Boolean(match && match[1].includes(declaration));
}

